sql:
SELECT score_availability, AVG(duration) AS average_duration
FROM scores
GROUP BY score_availability;

SELECT nationality, COUNT(composer_id) AS number_of_composers
FROM composers
GROUP BY nationality;

SELECT composer_name, biography
FROM composers
ORDER BY dob ASC;

